#include<bits/stdc++.h>
#define int long long
using namespace std;
const int MOD = 998244353;
int qp(int a,int b) 
{
    int res=1;
	while(b)
	{
		if(b&1)res=res*a%MOD;
		b=b>>1;a=(a*a)%MOD;
    }
	return res;
}
int cnt(int x)
{
    return ((x*(x+5)>>1)+1)%MOD;
}
int f(int n, int m) 
{
	if(m==0)return (f(n-1,1)+1)%MOD;
	if(m==1)return cnt(n);
	return ((n*qp(n+m,MOD-2))%MOD*cnt(n+m-1)%MOD+(m*qp(n+m,MOD-2))%MOD*f(n,m-1)+1)%MOD; 
}
int n,m;
signed main() 
{
	cin>>n>>m;
	cout<<f(n%MOD,m);
	return 0;
}
